let rawUrl = $input.first().json.body.url;

// Ensure string
rawUrl = typeof rawUrl === 'string' ? rawUrl : '';
rawUrl = rawUrl.trim();

if (!rawUrl) {
  return [{
    original_url: rawUrl,
    normalized_url: "",
    is_valid: false
  }];
}

let normalizedUrl = rawUrl;

// Add scheme if missing
if (!/^[a-zA-Z]+:\/\//.test(normalizedUrl)) {
  normalizedUrl = 'http://' + normalizedUrl;
}

// Lightweight validation without URL class or regex rules
let isValid = false;

try {
  // This trick works in restricted sandbox
  const parts = normalizedUrl.split('://');

  if (parts.length === 2) {
    const protocol = parts[0].toLowerCase();
    const hostPart = parts[1].split('/')[0];

    if (
      (protocol === 'http' || protocol === 'https') &&
      hostPart.length > 0 &&
      hostPart.includes('.')
    ) {
      isValid = true;
    }
  }

} catch (err) {
  isValid = false;
}

return [{
  original_url: rawUrl,
  normalized_url: normalizedUrl,
  is_valid: isValid
}];

