const stats = $json.data.attributes.stats;
const url_info  = $json.meta.url_info;

return [{
  vt_malicious: stats.malicious || 0,
  vt_suspicious: stats.suspicious || 0,
  vt_harmless: stats.harmless || 0,
  vt_undetected: stats.undetected || 0,
  vt_status: $json.data.attributes.status,
  url: url_info.url
}];

let risk = "Low";
let verdict = "SAFE";

const malicious = $json.vt_malicious || 0;
const suspicious = $json.vt_suspicious || 0;
let url = $json.url || "";

// High confidence phishing
if (malicious >= 3) {
  risk = "High";
  verdict = "PHISHING";
}

// Medium confidence suspicious (few malicious engines)
else if (malicious >= 1 && malicious <= 2) {
  risk = "Medium";
  verdict = "SUSPICIOUS";
}

// Medium confidence suspicious (multiple suspicious engines)
else if (suspicious >= 3) {
  risk = "Medium";
  verdict = "SUSPICIOUS";
}

// Defang the URL if verdict is NOT SAFE
if (verdict !== "SAFE") {
  // Simple defanging: replace . with [.] and hxxp:// instead of http
  url = url.replace(/^http:\/\//i, "hxxp://")
           .replace(/^https:\/\//i, "hxxps://")
           .replace(/\./g, "[.]");
}

return [{
  url,
  verdict,
  risk_level: risk,  
  engines: {
    virustotal: {
      malicious,
      suspicious
    }
  }
}];

